        <tr>
            <td>(P) $\alpha$ बराबर</td>
            <td>(1) $(-2, 4)$</td>
        </tr>
        <tr>
            <td>(Q) $r$ बराबर</td>
            <td>(2) $\sqrt{5}$</td>
        </tr>
        <tr>
            <td>(R) $A_1$ बराबर</td>
            <td>(3) $(-2, 6)$</td>
        </tr>
        <tr>
            <td>(S) $B_1$ बराबर</td>
            <td>(4) $5$</td>
        </tr>
        <tr>
